pw.test("Response has _version and data array with accepted_values", () => {
  const body = JSON.parse(pw.response.body);
  pw.expect(body._version).toBeDefined();
  pw.expect(Array.isArray(body.data)).toBe(true);
  pw.expect(body.data.length).toBeGreaterThan(0);
  body.data.forEach((field) => {
    pw.expect(field.name).toBeDefined();
    pw.expect(field.type).toBeDefined();
    pw.expect(field.description).toBeDefined();
    pw.expect(Array.isArray(field.accepted_values)).toBe(true);
    pw.expect(field.accepted_values.length).toBeGreaterThan(0);
    field.accepted_values.forEach((av) => {
      pw.expect(av.description).toBeDefined();
    });
  });
});

pw.test("Resource-backed fields have valid resource object", () => {
  const body = JSON.parse(pw.response.body);
  const resourceFields = body.data.filter((f) => f.resource);
  pw.expect(resourceFields.length).toBeGreaterThan(0);
  resourceFields.forEach((field) => {
    pw.expect(typeof field.resource.name).toBe("string");
    pw.expect(typeof field.resource.path).toBe("string");
    pw.expect(field.resource.path.startsWith("/")).toBe(true);
  });
});

